import RestoData from '../../data/resto-data';
import '../web-components/RestoCard.js';

const Home = {
  async renderPage() {
    return `
      <div class="introduction">
        <picture>
          <source media="(max-width: 600px)" srcset="./images/heros/hero-image_1-small.jpg">
          <img
          src="./images/heros/hero-image_1-medium.jpg"
          alt="Chefs preparing meals in the kitchen."
            />
        </picture>
        <div>
          <h2>
            Welcome to Tasty Trails – Your Guide to Unforgettable Dining
            Experiences!
          </h2>
          <p>
            Discover a world of flavors, ambiance, and culinary excellence
            right at your fingertips. Whether you're craving a cozy local
            café, an upscale dining experience, or hidden gems in your city,
            Tasty Trails is your trusted companion. We feature handpicked
            restaurants that offer the finest in taste, atmosphere, and
            service. From foodie favorites to new trends, embark on a
            delicious journey with us and find the perfect spot for every
            occasion. Explore, savor, and indulge!
          </p>
        </div>
      </div>
      <div class="resto-list" id="restoList"></div>`;
  },
  async afterRenderPage() {
    const restoListData = await RestoData.list();
    const restoListContainer = document.querySelector('#restoList');
    restoListData.forEach((restoData) => {
      const restoCard = document.createElement('resto-card');
      restoCard.lazyLoad = true;
      restoCard.restoData = restoData;
      restoListContainer.appendChild(restoCard);
    });
  },
};

export default Home;
