import DrawerInitiator from '../utils/drawer-initiator';
import UrlParser from '../routes/url-parser';
import routes from '../routes/routes';
import { heroImage } from './templates/templates';

class App {
  constructor({ hamburger, drawer, content, skipNav, hero }) {
    this._hamburger = hamburger;
    this._drawer = drawer;
    this._content = content;
    this._skipNav = skipNav,
    this._hero = hero,
    this._initialAppShell();
  }

  _initialAppShell() {
    DrawerInitiator.init({
      hamburger: this._hamburger,
      drawer: this._drawer,
      content: this._content,
      skipNav: this._skipNav
    });

    // kita bisa menginisiasikan komponen lain bila ada
  }
  async renderPage(){
    const url = UrlParser.parseActiveUrlWithCombiner();
    if (url === '/' || url === '/home'){
      this._hero.innerHTML = heroImage();
    } else {
      this._hero.innerHTML = '';
    }
    const page = routes[url];
    this._content.innerHTML = await page.renderPage();
    await page.afterRenderPage();
  }
}

export default App;