import FavoriteRestoIdb from '../../data/favorite-resto-idb';

const Favorites =  {
  async renderPage() {
    return '<div class="fav-resto-list" id="favRestoList"></div>';
  },
  async afterRenderPage() {
    const favRestos = await FavoriteRestoIdb.getAllRestos();
    const favRestoList = document.querySelector('#favRestoList');

    favRestos.forEach((restoData) => {
      const restoCard = document.createElement('resto-card');
      restoCard.restoData = restoData;
      favRestoList.appendChild(restoCard);
    });
  },
};

export default Favorites;